/* ===========================================================================
 * Upload control — keyboard accessibility (WCAG 2.1.1)
 *
 * Background (the bug these tests guard against): the file input was created
 * with `uploadInput.hidden = true`, which sets the HTML `hidden` attribute.
 * The UA stylesheet maps `[hidden]` to `display:none`, and a `display:none`
 * form control is removed from the tab order and cannot receive focus. The
 * only visible Upload affordance is a wrapping `<label class="btn">`, and
 * `<label>` elements are neither focusable nor activatable from the keyboard
 * on their own. Net effect: keyboard-only and screen-reader users could not
 * reach or trigger Upload — a WCAG 2.1.1 (Keyboard) failure — while mouse
 * users could (a `<label>` click forwards to its wrapped input).
 *
 * The fix keeps the input in the accessibility tree and tab order by hiding
 * it *visually* with the standard `visually-hidden` (sr-only) clip pattern
 * rather than the `hidden` attribute, and gives it an `aria-label` so it has
 * an accessible name. Because the `<label class="btn">` still wraps the input,
 * Tab moves focus onto the (visually hidden) input inside the visible Upload
 * button, and Enter/Space opens the file picker. The matching CSS contract
 * — that `.visually-hidden` clips rather than `display:none`s the element,
 * and that the Upload label shows a focus ring via `:focus-within` — lives in
 * `src/app.css.test.ts`.
 *
 * Environment note: happy-dom does NOT model the UA `display:none` for
 * `[hidden]` (a hidden input still reports `getComputedStyle(...).display` as
 * `inline-block`) nor enforce the "hidden elements cannot receive focus"
 * rule. It also reports the `tabIndex` IDL property as -1 for file inputs no
 * matter whether `[hidden]` is set, so these tests assert against the content
 * attributes and classes (no `hidden` attribute + `visually-hidden` class +
 * accessible name + not disabled + no explicit negative tabindex + no inline
 * `display:none`/`visibility:hidden` style) — the *mechanisms* that produce
 * correct behavior in a real browser — rather than observing tab-order /
 * focus-ring rendering, which only a real browser would reflect. The change →
 * handleUpload upload behavior itself is exercised in `toolbar-handlers.test.ts`.
 * ========================================================================= */
describe('upload control — keyboard accessibility', () => {
  /* The input must remain in the tab order. The `hidden` HTML attribute is the
     exact mechanism that broke keyboard access (UA display:none), so its
     absence is the core assertion of this suite. */
  describe('the file input is NOT removed from the tab order', () => {
    it('does not carry the `hidden` HTML attribute', () => {
      const { uploadInput } = setup();
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
    });

    it('the `hidden` IDL property is false', () => {
      const { uploadInput } = setup();
      expect(uploadInput.hidden).toBe(false);
    });

    it('is visually hidden via the `visually-hidden` sr-only class instead', () => {
      const { uploadInput } = setup();
      expect(uploadInput.classList.contains('visually-hidden')).toBe(true);
    });

    it('carries no negative tabindex attribute (which would remove it from the tab order)', () => {
      const { uploadInput } = setup();
      // A file input with no tabindex attribute is naturally focusable; ANY
      // negative tabindex ("-1", "-2", "-5", ...) is a different vector for the
      // same WCAG 2.1.1 failure (it removes the control from the sequential
      // focus order). Assert against the content attribute rather than the IDL
      // `tabIndex`: happy-dom reports `tabIndex` as -1 for file inputs no
      // matter whether the `hidden` attribute is set, so only the attribute is
      // a reliable signal here. `null` (no attribute) is the focusable default
      // and satisfies the contract; a non-negative explicit value does too.
      const tabindex = uploadInput.getAttribute('tabindex');
      expect(tabindex === null || Number(tabindex) >= 0).toBe(true);
    });

    it('is not `disabled` (a disabled form control is also unfocusable)', () => {
      const { uploadInput } = setup();
      // `disabled` is a distinct vector for the same WCAG 2.1.1 failure: a
      // disabled input cannot receive focus and is skipped by Tab. The fix must
      // keep the control enabled regardless of how it is hidden visually.
      expect(uploadInput.disabled).toBe(false);
      expect(uploadInput.hasAttribute('disabled')).toBe(false);
    });

    it('carries no inline `style` declaring display:none or visibility:hidden', () => {
      const { uploadInput } = setup();
      // The class-based `visually-hidden` fix is the only intended hiding
      // mechanism. An inline `style="display:none"` (or `visibility:hidden` —
      // both of which remove an element from the tab order) would re-introduce
      // the keyboard failure independently of the class, so guard against a
      // regression that adds either via the style property.
      const inlineStyle = uploadInput.getAttribute('style') ?? '';
      expect(/display\s*:\s*none/.test(inlineStyle)).toBe(false);
      expect(/visibility\s*:\s*hidden/.test(inlineStyle)).toBe(false);
    });
  });

  /* An unnamed form control is announced generically by screen readers (e.g.
     "file upload button"). The visible text lives on the wrapping label, but
     the input itself — the actual focus target — needs its own accessible
     name now that it is the element Tab lands on. */
  describe('the file input has an accessible name', () => {
    it('exposes aria-label="Upload files"', () => {
      const { uploadInput } = setup();
      expect(uploadInput.getAttribute('aria-label')).toBe('Upload files');
    });

    it('the aria-label is a non-empty, non-whitespace string', () => {
      // Guards against a regression that sets aria-label="" or "   ", which is
      // worse than no label (an empty accessible name can override a
      // label-derived name in the name computation).
      const { uploadInput } = setup();
      const label = uploadInput.getAttribute('aria-label') ?? '';
      expect(label.length).toBeGreaterThan(0);
      expect(label.trim().length).toBeGreaterThan(0);
    });

    it('does not also set aria-hidden (which would exclude it from the a11y tree)', () => {
      const { uploadInput } = setup();
      expect(uploadInput.getAttribute('aria-hidden')).toBeNull();
    });
  });

  /* The visible Upload affordance must still wrap the input so the label's
     click-forwarding and visible "Upload" text keep working for mouse and AT
     users, and so Tab lands inside the visible button. */
  describe('the visible Upload label still wraps the input', () => {
    it('the input is a descendant of the label.btn "Upload" affordance', () => {
      const { uploadLabel, uploadInput } = setup();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.textContent).toContain('Upload');
      expect(uploadLabel.contains(uploadInput)).toBe(true);
    });

    it('there is exactly one file input, nested inside the Upload label', () => {
      const { root, uploadInput, uploadLabel } = setup();
      const fileInputs = root.querySelectorAll('input[type="file"]');
      expect(fileInputs).toHaveLength(1);
      expect(fileInputs[0]).toBe(uploadInput);
      expect(uploadLabel.contains(fileInputs[0])).toBe(true);
    });
  });

  /* The hiding mechanism is the ONLY thing that changes; the control's type,
     multiplicity, and change-handler wiring must be preserved. */
  describe('upload behavior is preserved', () => {
    it('retains type=file and multiple', () => {
      const { uploadInput } = setup();
      expect(uploadInput.type).toBe('file');
      expect(uploadInput.hasAttribute('multiple')).toBe(true);
    });

    it('still dispatches `change` to the upload handler (wiring unchanged)', () => {
      // The fix only changes how the input is *hidden*; the change listener
      // bound in startApp must remain attached. Dispatching `change` with no
      // files is a no-op for handleUpload, so this asserts the listener is
      // wired without coupling to the upload network round-trip.
      const { uploadInput } = setup({ hash: '#/browse/' });
      expect(() => uploadInput.dispatchEvent(new Event('change'))).not.toThrow();
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'a & b=c?';
      searchBtn.click();

      const expected =
        '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
      expect(window.location.hash).toBe(expected);
      expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
    });
  });
});

/* ===========================================================================
 * Dead CSS selector characterization
 *
 * `src/app.css` ships rule blocks whose selectors are NEVER emitted by app.ts,
 * so they have ZERO observable effect on the rendered UI. They are slated for
 * deletion in a dead-code cleanup. The tests below pin the JS-side invariants
 * that make that deletion provably safe:
 *
 *   - the rendered DOM must never produce an element the removed selectors
 *     could match; and
 *   - any behavior the dead rules *appear* to supply must actually be provided
 *     by an independent mechanism that survives the deletion.
 *
 * Removed selectors under test:
 *   (1) `.results-table .folder-row td`  — no table row is ever given the
 *       `folder-row` class.
 *   (2) `.breadcrumb .separator`         — breadcrumb separators are class-less
 *       `<span>`s holding the literal "/"; nothing carries `separator`.
 *   (3) `.toolbar label.upload-btn` (+ its `:hover` + the descendant
 *       `input[type=file]` rule) — the upload label uses `btn`, never
 *       `upload-btn`, and the wrapped file input is hidden via the `hidden`
 *       HTML attribute, not via the dead `display:none` descendant rule.
 *
 * These assertions pass against the current (pre-cleanup) code AND must keep
 * passing after the dead rules are deleted, because they depend only on the
 * DOM app.ts emits — which the cleanup does not touch. (The environment does
 * not load app.css, so a missing rule cannot change `getComputedStyle` here;
 * these tests instead prove the rule could never have matched anything.)
 *
 * NOTE: these tests pass a `Route` fixture (`browseRoute` / `searchRoute`) as
 * a second argument to `renderBrowse` / `renderSearch`. That argument is a
 * leftover from before the route parameter was removed (see the
 * route-independence suite in `render-orchestration.test.ts`) and is silently
 * ignored at runtime; it is preserved verbatim so the scenario is unchanged.
 * ========================================================================= */
describe('dead CSS selector characterization', () => {
  describe('folder rows never carry the dead `.folder-row` class', () => {
    it('browse rows (folder, file, and the ".." parent) all have an empty className and no `folder-row`', async () => {
      const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
      const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
      const { results } = await setupCleared();
      renderBrowse(
        browseResult({ path: 'docs/sub', parent: 'docs', entries: [dir, file] }),
        browseRoute('docs/sub'),
      );

      const rows = dataRows(results.querySelector('table')!);
      // parent + folder + file = 3 rows, so the assertions below are meaningful.
      expect(rows).toHaveLength(3);
      for (const row of rows) {
        expect(row.className).toBe('');
        expect(row.classList.contains('folder-row')).toBe(false);
      }
      // The dead selector `.results-table .folder-row td` matches nothing.
      expect(document.querySelectorAll('.folder-row')).toHaveLength(0);
    });

    it('search rows also never carry the `folder-row` class', async () => {
      const dir = fileEntry({ name: 'd', path: 'docs/d', isDirectory: true });
      const file = fileEntry({ name: 'f.txt', path: 'docs/f.txt', isDirectory: false });
      const { results } = await setupCleared();
      renderSearch({ query: 'q', path: '', results: [dir, file] }, searchRoute('q'));

      const rows = dataRows(results.querySelector('table')!);
      expect(rows).toHaveLength(2);
      for (const row of rows) {
        expect(row.classList.contains('folder-row')).toBe(false);
      }
      expect(document.querySelectorAll('.folder-row')).toHaveLength(0);
    });
  });

  describe('breadcrumb separators are class-less spans (no `.separator`)', () => {
    /** Leaf <span>s whose visible text is exactly the breadcrumb slash. */
    function slashSeparators(container: Element): HTMLSpanElement[] {
      return Array.from(container.querySelectorAll('span')).filter(
        (s) => (s.textContent ?? '').trim() === '/',
      ) as HTMLSpanElement[];
    }

    it('renders one "/" separator per path segment, each a class-less <span>', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }), browseRoute('a/b/c'));

      const separators = slashSeparators(breadcrumb);
      // a/b/c → 3 segments → 3 separators (Home / a / b / c). Verifying the
      // count also pins that the separators are still visibly rendered.
      expect(separators).toHaveLength(3);
      for (const sep of separators) {
        expect(sep.tagName).toBe('SPAN');
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      // The dead selector `.breadcrumb .separator` matches nothing.
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('renders no separators for the root path, and still no `.separator` anywhere', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '', entries: [] }), browseRoute(''));

      expect(slashSeparators(breadcrumb)).toHaveLength(0);
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('search-scope breadcrumbs also use class-less "/" separators', async () => {
      const { breadcrumb } = await setupCleared();
      renderSearch({ query: 'q', path: 'x/y', results: [] }, searchRoute('q', 'x/y'));

      const separators = slashSeparators(breadcrumb);
      expect(separators).toHaveLength(2);
      for (const sep of separators) {
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });
  });

  describe('upload control never carries the dead `upload-btn` class', () => {
    it('the upload label uses `btn` (styled by .btn), and no element is `upload-btn`', () => {
      const { uploadLabel } = setup();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
      // The dead selector `.toolbar label.upload-btn` matches nothing.
      expect(document.querySelectorAll('.upload-btn')).toHaveLength(0);
    });

    it('hides the file input via the `visually-hidden` class — NOT the dead `display:none` rule, NOT the `hidden` attribute', () => {
      const { uploadInput, uploadLabel } = setup();
      // The input is visually hidden via the `visually-hidden` sr-only class
      // (a clip-to-1x1 pattern that keeps it focusable for keyboard users —
      // see upload-a11y.test.ts), NOT via the `hidden` HTML attribute (UA
      // `display:none` would eject it from the tab order). Because the hiding
      // is done by the input's own class, deleting the dead descendant rule
      // `.toolbar label.upload-btn input[type=file] { display: none; }` cannot
      // un-hide it.
      expect(uploadInput.hidden).toBe(false);
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
      expect(uploadInput.className).toContain('visually-hidden');
      // The dead descendant selector `.toolbar label.upload-btn input[type=file]`
      // still cannot match this input: its label ancestor is `btn`, never
      // `upload-btn`, so the selector never applied regardless of the input's
      // own class. Deleting that dead rule cannot un-hide it.
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
    });
  });
});

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement | undefined =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement | undefined;

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search') as HTMLButtonElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find((tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name);
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () => mockResponse({ body: {} }));

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, handleUpload } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  const uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.multiple = true;
  // Visually hidden via the sr-only clip pattern (the `visually-hidden`
  // class) rather than the `hidden` HTML attribute: the attribute's UA
  // `display:none` ejects the control from the tab order, leaving Upload
  // unreachable via keyboard (WCAG 2.1.1). The class clips it to a 1x1 box
  // so it stays focusable; the visible "Upload" affordance is this wrapping
  // label.btn, and `.toolbar label.btn:focus-within` reflects focus onto it.
  uploadInput.classList.add('visually-hidden');
  // The input is now the element Tab lands on, so it needs its own accessible
  // name (the label text alone doesn't name a focusable input reliably).
  uploadInput.setAttribute('aria-label', 'Upload files');
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
    uploadInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

/**
 * Render a {@link BrowseResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Size | Modified | Actions) with an
 * optional leading ".." parent row.
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { BrowseResult } from '../api.js';
import { formatBytes } from '../format.js';
import { buildTable, makeBrowseRow, makeParentRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderBrowse(result: BrowseResult): void {
  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  getStatus().textContent =
    result.folderCount +
    ' folders, ' +
    result.fileCount +
    ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/**
 * Pure DOM-construction helpers for the file-browser tables, breadcrumb, and
 * action controls.
 *
 * Every function here builds and returns a DOM subtree (or, for
 * `renderBreadcrumb`, populates the shared breadcrumb element from the
 * context). They hold no state of their own; the shared element refs and API
 * client are read from `./context.js`.
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 */
import type { FileEntry } from '../api.js';
import { formatBytes, formatDate, joinPath, normalizeRelativePath } from '../format.js';
import { navigate, toBrowseHash } from '../router.js';
import { getApi, getBreadcrumb, getStatus, rerender } from './context.js';

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. The caller appends rows to the `<tbody>`.
 */
export function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  table.className = 'results-table';
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into the shared breadcrumb element: a
 * leading "Home" link (root) followed by one link per path segment, each
 * navigating to its cumulative path. Separators are plain '/' text spans.
 */
export function renderBreadcrumb(path: string): void {
  const breadcrumbEl = getBreadcrumb();
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
  }
}

/**
 * Build an `<a>` that navigates to `hash` on click. The `href` is set via
 * `setAttribute` (so the raw attribute is preserved exactly — important for
 * download URLs that must not be URL-normalized) and a click handler calls
 * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
 * implementations. The href also enables middle-click / copy-link support.
 */
export function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
export function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** One data row in the browse table (a file or folder entry). */
export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', getApi().downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(
    makeActionButton('Delete', async () => {
      if (!window.confirm('Delete "' + entry.name + '"?')) {
        return;
      }
      await getApi().delete(entry.path);
      rerender();
    }),
  );
  actionsCell.append(
    makeActionButton('Move', async () => {
      const dest = window.prompt('Move to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().move(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );
  actionsCell.append(
    makeActionButton('Copy', async () => {
      const dest = window.prompt('Copy to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().copy(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/**
 * Build a `<button class="btn">` with the given label and click handler.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 */
export function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = label;
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/** One data row in the search-results table. */
export function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', getApi().downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (dom-builders,
 * render-browse, render-search, toolbar-handlers, render-orchestrator). They
 * all need access to three cross-cutting things that `startApp` establishes
 * once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input, upload input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → dom-builders → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit — replacing the bare
 * module-level `let resultsEl!: HTMLElement` variables that used to live in
 * `app.ts`. `render-orchestrator.init` re-binds the refs every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  uploadInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load, exactly as the original `app.ts` created
 * `const api = new ApiClient();` at its top level. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions mirror the original `let resultsEl!:
 * HTMLElement` pattern: the refs are uninitialized only until the first
 * `init()` call, which always runs before any render helper reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;
let uploadInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
  uploadInput = refs.uploadInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

export function getUploadInput(): HTMLInputElement {
  return uploadInput;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (in dom-builders) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}

/**
 * Tests for the rendering layer's coordination: the `render()` route-dispatch
 * lifecycle (initial render, navigation dispatch, error display, clearing of
 * previous results), the render-race guard and hashchange-listener cleanup, and
 * the route-independence characterization of `renderBrowse`/`renderSearch`.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from '../app';
import type { SearchResult } from '../api';
import { toBrowseHash, toSearchHash, navigate } from '../router';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  joinPathHelper,
  dataRows,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * render output depends ONLY on `result` (route-parameter removal)
 *
 * Characterization for the removal of the unused `route` parameter from
 * `renderBrowse`/`renderSearch`. Before the refactor each function accepted a
 * `route: Route` that it discarded (`void route`); after the refactor the
 * parameter is gone. The observable contract is unchanged either way:
 * EVERYTHING the functions render — breadcrumb, status footer, and the results
 * table — is derived solely from the `result` argument. They must not read the
 * active route (getCurrentRoute / window.location.hash), so the rendered DOM is
 * identical no matter what hash is set when they run. The route-independence
 * tests below pin that by rendering the same `result` under different active
 * routes and asserting byte-for-byte identical output; the remaining tests add
 * result-only edge cases (empty results, search scope path, table swapping).
 * ========================================================================= */
describe('render output depends only on result (route is irrelevant)', () => {
  it('renderBrowse produces identical output regardless of the active route', async () => {
    const result = browseResult({
      path: 'docs/sub',
      parent: 'docs',
      entries: [
        fileEntry({ name: 'a.txt', path: 'docs/sub/a.txt', size: 2048 }),
        fileEntry({ name: 'folder', path: 'docs/sub/folder', isDirectory: true }),
      ],
      folderCount: 1,
      fileCount: 1,
      totalSize: 2048,
    });

    // Start under a SEARCH route, render the browse result, and snapshot it.
    const { results, status, breadcrumb } = await setupCleared({
      hash: toSearchHash('whatever', 'else/where'),
    });
    renderBrowse(result);
    const snapResults = results.innerHTML;
    const snapStatus = status.textContent;
    const snapBreadcrumb = breadcrumb.innerHTML;

    // Switch to a completely different active route (a browse route) and let the
    // background render settle, then re-render the SAME result. renderBrowse
    // derives everything from `result`, so the output must be byte-for-byte
    // identical despite the route change.
    window.location.hash = toBrowseHash('completely/different/path');
    await flush();
    results.innerHTML = '';
    renderBrowse(result);

    expect(results.innerHTML).toBe(snapResults);
    expect(status.textContent).toBe(snapStatus);
    expect(breadcrumb.innerHTML).toBe(snapBreadcrumb);
    // Non-trivial sanity: the output is actually populated (not two empties).
    expect(results.querySelector('table')).toBeTruthy();
    expect(breadcrumb.querySelectorAll('a').length).toBeGreaterThan(0);
  });

  it('renderSearch produces identical output regardless of the active route', async () => {
    const result: SearchResult = {
      query: 'kittens',
      path: 'pets',
      results: [fileEntry({ name: 'cat.txt', path: 'pets/cat.txt', size: 4096 })],
    };

    // Start under a BROWSE route, render the search result, and snapshot it.
    const { results, status, breadcrumb } = await setupCleared({
      hash: toBrowseHash('unrelated/browse/route'),
    });
    renderSearch(result);
    const snapResults = results.innerHTML;
    const snapStatus = status.textContent;
    const snapBreadcrumb = breadcrumb.innerHTML;

    // Switch to a different active route (a search route) and let the background
    // render settle, then re-render the SAME result. renderSearch derives
    // everything from `result`, so the output must be identical.
    window.location.hash = toSearchHash('different', 'query/scope');
    await flush();
    results.innerHTML = '';
    renderSearch(result);

    expect(results.innerHTML).toBe(snapResults);
    expect(status.textContent).toBe(snapStatus);
    expect(breadcrumb.innerHTML).toBe(snapBreadcrumb);
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('renderSearch breadcrumb reflects result.path (search scope), not the route', async () => {
    // The search scope path comes from result.path. With an empty hash and a
    // result scoped to 'archive/2024', the breadcrumb must show those segments
    // — proving the scope is sourced from result, not the active route.
    const { breadcrumb } = await setupCleared({ hash: '' });
    renderSearch({ query: 'q', path: 'archive/2024', results: [] });

    const texts = Array.from(breadcrumb.querySelectorAll('a')).map(
      (el) => el.textContent?.trim() ?? '',
    );
    expect(texts).toContain('Home');
    expect(texts).toContain('archive');
    expect(texts).toContain('2024');
  });

  describe('result-only status / footer edge cases', () => {
    it('renderBrowse with an empty result reports zero totals and no data rows', async () => {
      const { status, results } = await setupCleared();
      renderBrowse(
        browseResult({
          path: '',
          parent: null,
          entries: [],
          folderCount: 0,
          fileCount: 0,
          totalSize: 0,
        }),
      );

      expect(status.textContent).toBe('0 folders, 0 files, total 0 B');
      // Header row only — no data rows and no ".." parent row.
      expect(dataRows(results.querySelector('table')!)).toHaveLength(0);
    });

    it('renderSearch with zero results reports "0 results for ..." and no data rows', async () => {
      const { status, results } = await setupCleared();
      renderSearch({ query: 'nothing-here', path: '', results: [] });

      expect(status.textContent).toBe('0 results for "nothing-here"');
      expect(dataRows(results.querySelector('table')!)).toHaveLength(0);
    });
  });

  describe('re-render replaces prior output (direct call)', () => {
    /* render() dispatches to renderBrowse or renderSearch depending on the
       route; whichever runs must REPLACE the other's table rather than stack a
       second one. These pin the swap at the direct-call level (the render()
       orchestration suite covers the navigation-driven path). */
    it('renderSearch after renderBrowse swaps columns and status, leaving one table', async () => {
      const { results, status } = await setupCleared();
      renderBrowse(
        browseResult({
          path: 'docs',
          entries: [fileEntry({ name: 'a.txt', size: 10 })],
          fileCount: 1,
          totalSize: 10,
        }),
      );
      expect(status.textContent).toContain('1 files');
      let headers = Array.from(results.querySelectorAll('th')).map((h) => h.textContent!.trim());
      expect(headers).toEqual(['Name', 'Size', 'Modified', 'Actions']);

      renderSearch({
        query: 'q',
        path: '',
        results: [fileEntry({ name: 'a.txt', path: 'docs/a.txt' })],
      });
      headers = Array.from(results.querySelectorAll('th')).map((h) => h.textContent!.trim());
      expect(headers).toEqual(['Name', 'Path', 'Size', 'Modified']);
      expect(status.textContent).toContain('1 results for "q"');
      // Exactly one table — the previous browse table was replaced, not stacked.
      expect(results.querySelectorAll('table')).toHaveLength(1);
    });

    it('renderBrowse after renderSearch swaps columns and status, leaving one table', async () => {
      const { results, status } = await setupCleared();
      renderSearch({
        query: 'q',
        path: '',
        results: [fileEntry({ name: 'a.txt', path: 'docs/a.txt' })],
      });
      expect(status.textContent).toContain('1 results for "q"');

      renderBrowse(
        browseResult({
          path: 'docs',
          entries: [fileEntry({ name: 'a.txt', size: 10 })],
          fileCount: 1,
          totalSize: 10,
        }),
      );
      const headers = Array.from(results.querySelectorAll('th')).map((h) => h.textContent!.trim());
      expect(headers).toEqual(['Name', 'Size', 'Modified', 'Actions']);
      expect(status.textContent).toContain('1 files');
      expect(results.querySelectorAll('table')).toHaveLength(1);
    });
  });
});

/* ===========================================================================
 * render() orchestration (subscribe + initial render + dispatch + errors)
 * ========================================================================= */
describe('render orchestration', () => {
  it('renders browse results for the initial route on startApp', async () => {
    const { results } = setup({ hash: toBrowseHash('home') });
    await flush();

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    // The default mock derives an entry name from the requested path.
    expect(results.textContent).toContain('child-of-home');
    expect(
      fetchMock.mock.calls.some(
        ([u]) =>
          String(u).includes('/browse') && String(u).includes('path=' + encodeURIComponent('home')),
      ),
    ).toBe(true);
  });

  it('re-renders into search results after navigating to a search hash', async () => {
    const { results, status } = setup();
    await flush();

    navigate(toSearchHash('kittens', ''));
    await flush();

    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-kittens');
    expect(status.textContent).toContain('kittens');
  });

  it('shows an error message in .results (and no table) when the API call fails', async () => {
    fetchMock.mockImplementation(async () => mockResponse({ status: 500, text: 'boom' }));
    const { results } = setup();
    await flush();

    expect(results.querySelector('table')).toBeNull();
    expect((results.textContent ?? '').trim().length).toBeGreaterThan(0);
  });

  it('clears previous results before rendering the new route', async () => {
    const { results } = setup();
    await flush();

    navigate(toBrowseHash('first'));
    await flush();
    expect(results.querySelectorAll('table')).toHaveLength(1);

    navigate(toBrowseHash('second'));
    await flush();
    expect(results.querySelectorAll('table')).toHaveLength(1); // not accumulated
    expect(results.textContent).toContain('child-of-second');
  });
});

/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it("unsubscribes the previous mount's hashchange listener on every re-mount", async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(heldPath: string): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

/**
 * Tests for `renderSearch` — the search-result renderer (table headers, rows,
 * per-result columns, directory-name navigation, file-name download, and the
 * status footer).
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded here (carried over from the monolith):
 *  - Clicking a directory result name navigates (asserted via
 *    `window.location.hash`); clicking a search-result FILE name opens its
 *    download URL. The spec does not pin the file-open mechanism, so that test
 *    accepts EITHER an `<a href={downloadUrl}>` OR a `window.open(downloadUrl)`
 *    call.
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for search is
 *    `Name | Path | Size | Modified`.
 *  - `renderSearch` operates against the DOM context `startApp` establishes
 *    (module-level element refs), so every test calls `setupCleared()` first.
 */
import { describe, it, expect, vi } from 'vitest';
import { renderSearch } from '../app';
import type { FileEntry } from '../api';
import { toBrowseHash } from '../router';
import {
  setupCleared,
  fileEntry,
  dataRows,
  cellsOf,
  rowByName,
  clickNameLink,
  ISO_FMT,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * renderSearch — table, rows, navigation
 * ========================================================================= */
describe('renderSearch', () => {
  it('builds a table with header Name | Path | Size | Modified', async () => {
    const { results } = await setupCleared();
    renderSearch({ query: 'foo', path: '', results: [] });

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    const headers = Array.from(table!.querySelectorAll('th')).map((h) => h.textContent!.trim());
    expect(headers).toEqual(['Name', 'Path', 'Size', 'Modified']);
  });

  it('renders one row per result with its path, size and modified date', async () => {
    const results_data: FileEntry[] = [
      fileEntry({ name: 'a.txt', path: 'docs/a.txt', size: 1536 }),
      fileEntry({ name: 'b.txt', path: 'other/b.txt', size: 0 }),
    ];
    const { results } = await setupCleared();
    renderSearch({ query: 'q', path: '', results: results_data });

    const table = results.querySelector('table')!;
    expect(dataRows(table)).toHaveLength(2);
    const cells = cellsOf(rowByName(table, 'a.txt')!);
    expect(cells[1].textContent?.trim()).toBe('docs/a.txt'); // Path
    expect(cells[2].textContent?.trim()).toBe('1.5 KB'); // Size
    expect(cells[3].textContent?.trim()).toBe(ISO_FMT); // Modified
  });

  it('clicking a directory result name navigates to toBrowseHash(entry.path)', async () => {
    const dir = fileEntry({ name: 'matchdir', path: 'docs/matchdir', isDirectory: true });
    const { results } = await setupCleared();
    renderSearch({ query: 'match', path: '', results: [dir] });

    clickNameLink(rowByName(results.querySelector('table')!, 'matchdir')!);
    expect(window.location.hash).toBe(toBrowseHash('docs/matchdir'));
  });

  it('clicking a file result name opens api.downloadUrl(entry.path)', async () => {
    const file = fileEntry({ name: 'match.txt', path: 'docs/match.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderSearch({ query: 'match', path: '', results: [file] });
    const expectedUrl = '/api/files/download?path=' + encodeURIComponent('docs/match.txt');

    const nameCell = cellsOf(rowByName(results.querySelector('table')!, 'match.txt')!)[0];
    const link = nameCell.querySelector('a, button') as HTMLElement | null;
    expect(link).toBeTruthy();

    // The spec says clicking "opens" the download URL. Two reasonable mechanisms
    // are acceptable: an <a href={downloadUrl}> (mirroring the Download control)
    // or a click handler that calls window.open(downloadUrl). Accept either so
    // the test does not over-constrain the implementation choice.
    const hrefOpens = link!.getAttribute('href') === expectedUrl;
    const openSpy = vi.spyOn(window, 'open').mockReturnValue(null);
    link!.click();
    const openedViaWindow = openSpy.mock.calls.some((c) => c[0] === expectedUrl);
    expect(hrefOpens || openedViaWindow).toBe(true);
  });

  it('shows the result count and query in the status footer', async () => {
    const { status } = await setupCleared();
    renderSearch({
      query: 'foo',
      path: '',
      results: [fileEntry({ name: 'a.txt' }), fileEntry({ name: 'b.txt' })],
    });

    expect(status.textContent).toContain('2 results for "foo"');
  });
});

/**
 * Static-asset tests for `src/app.css` — guards against a subtle native-<dialog>
 * CSS regression.
 *
 * A closed `<dialog>` is hidden by the UA rule `dialog:not([open]){display:none}`.
 * But an AUTHOR `display` declaration overrides the UA stylesheet regardless of
 * specificity, so setting `display` on the base `.browser-dialog` rule keeps the
 * closed dialog (and therefore its frame/titlebar) visible on the page — the
 * "frame in the middle of the screen with no dialog open" bug.
 *
 * The contract under test:
 *   - the base `.browser-dialog { ... }` rule (selector without `[open]`) must
 *     NOT declare `display`;
 *   - the flex-column layout must live on `.browser-dialog[open]` so it only
 *     applies while the dialog is shown.
 *
 * These tests parse the raw CSS string (the vitest environment does not load
 * app.css, so `getComputedStyle` cannot observe author rules), matching the
 * approach used in `index.html.test.ts`.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const CSS_PATH = resolve(__dirname, './app.css');
const CSS = readFileSync(CSS_PATH, 'utf8');

/**
 * Extract the declaration block of the FIRST rule whose selector matches the
 * given selector regex anchor, stopping at the first `}`. Returns null if no
 * such rule exists.
 *
 * `anchor` must match the selector up to (but not including) the opening brace;
 * callers pass a regex that is anchored to avoid prefix collisions (e.g. the
 * base `.browser-dialog` rule must not be confused with `.browser-dialog[open]`
 * or `.browser-dialog .dialog-body`).
 */
function ruleDeclarations(selectorRegex: RegExp): string | null {
  const re = new RegExp(selectorRegex.source + '\\s*\\{([^}]*)\\}');
  const m = CSS.match(re);
  return m ? m[1] : null;
}

describe('src/app.css — native <dialog> visibility contract', () => {
  it('the base .browser-dialog rule does NOT declare display', () => {
    // Selector must be exactly `.browser-dialog` followed by `{` — the negative
    // lookahead prevents matching `.browser-dialog[open]`, `.browser-dialog .x`,
    // or `.browser-dialog::backdrop`.
    const base = ruleDeclarations(/\.browser-dialog(?![\w[#.])/);
    expect(base, 'a base .browser-dialog { ... } rule must exist').not.toBeNull();
    expect(
      /display\s*:/.test(base!),
      'the base .browser-dialog rule must not set `display` — that would override ' +
        'the UA `dialog:not([open]){display:none}` and render the closed dialog visible',
    ).toBe(false);
  });

  it('the flex-column layout is scoped to .browser-dialog[open]', () => {
    const open = ruleDeclarations(/\.browser-dialog\[open\]/);
    expect(open, 'a .browser-dialog[open] { ... } rule must exist').not.toBeNull();
    expect(/display\s*:\s*flex/.test(open!), 'open dialog must use display:flex').toBe(true);
    expect(/flex-direction\s*:\s*column/.test(open!), 'open dialog must be a flex column').toBe(
      true,
    );
  });
});

/* ===========================================================================
 * Upload control — keyboard accessibility contract
 *
 * The file input is visually hidden via a `visually-hidden` (sr-only) class
 * instead of the `hidden` HTML attribute, precisely so it STAYS in the tab
 * order and is keyboard-focusable (the `hidden` attribute's UA `display:none`
 * made Upload unreachable via keyboard — WCAG 2.1.1). These tests pin the
 * CSS half of that contract by parsing the raw stylesheet:
 *
 *   - `.visually-hidden` must use the standard clip-to-1x1 sr-only pattern
 *     (position:absolute + width/height:1px + clip:rect(0,0,0,0) + overflow:
 *     hidden + white-space:nowrap). Crucially it must NOT use `display:none`
 *     NOR `visibility:hidden` — both of which remove an element from the tab
 *     order and would re-introduce the exact bug the class exists to avoid.
 *   - `.toolbar label.btn:focus-within` must apply a visible focus indicator
 *     so a sighted keyboard user can see that focus has landed on the Upload
 *     button (the input itself is clipped to 1x1, so its own focus outline is
 *     not a reliable signal; the wrapping label must reflect the focus).
 *
 * As above, the raw CSS is parsed because the vitest environment does not load
 * app.css, so `getComputedStyle` cannot observe author rules.
 * ========================================================================= */
describe('src/app.css — upload control keyboard accessibility', () => {
  describe('.visually-hidden uses the sr-only clip pattern (NOT display:none / visibility:hidden)', () => {
    it('a .visually-hidden rule exists', () => {
      // Negative lookahead so `.visually-hidden` is not confused with a
      // hypothetical `.visually-hidden-something` descendant/compound selector.
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/);
      expect(rule, 'a .visually-hidden { ... } rule must exist').not.toBeNull();
    });

    it('positions the element absolutely and clips it to a 1x1 box (sr-only pattern)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(/position\s*:\s*absolute/.test(rule), 'position:absolute').toBe(true);
      expect(/width\s*:\s*1px/.test(rule), 'width:1px').toBe(true);
      expect(/height\s*:\s*1px/.test(rule), 'height:1px').toBe(true);
      expect(/overflow\s*:\s*hidden/.test(rule), 'overflow:hidden').toBe(true);
      expect(/clip\s*:\s*rect\(/.test(rule), 'clip:rect(...)').toBe(true);
      expect(/white-space\s*:\s*nowrap/.test(rule), 'white-space:nowrap').toBe(true);
    });

    it('collapses padding/margin/border so the 1x1 box carries no visible footprint', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(/padding\s*:\s*0/.test(rule), 'padding:0').toBe(true);
      expect(/border\s*:\s*0/.test(rule), 'border:0').toBe(true);
      // margin is typically -1px to pull the 1x1 box fully out of flow.
      expect(/margin\s*:\s*-1px/.test(rule), 'margin:-1px').toBe(true);
    });

    it('does NOT use display:none (which would re-introduce the keyboard-inaccessibility bug)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(
        /display\s*:\s*none/.test(rule),
        'visually-hidden must NOT use display:none — that removes the element from ' +
          'the tab order, which is exactly the keyboard failure the class exists to avoid',
      ).toBe(false);
    });

    it('does NOT use visibility:hidden (which also ejects the element from the tab order)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      // `visibility:hidden` has the same effect as `display:none` for keyboard
      // access: an element with `visibility:hidden` cannot receive focus and is
      // removed from the sequential focus order. The classic sr-only clip
      // pattern intentionally omits it (it clips with `overflow:hidden` +
      // `clip:rect(0,0,0,0)` instead), so its presence would re-introduce the
      // exact bug the class exists to fix.
      expect(
        /visibility\s*:\s*hidden/.test(rule),
        'visually-hidden must NOT use visibility:hidden — like display:none, an element ' +
          'with visibility:hidden is removed from the tab order and cannot receive focus',
      ).toBe(false);
    });
  });

  describe('.toolbar label.btn shows a visible focus ring when its input is focused', () => {
    it('a .toolbar label.btn:focus-within rule exists', () => {
      const rule = ruleDeclarations(/\.toolbar\s+label\.btn:focus-within/);
      expect(
        rule,
        'a .toolbar label.btn:focus-within { ... } rule must exist so the Upload ' +
          'button shows focus when the (clipped) input inside it receives keyboard focus',
      ).not.toBeNull();
    });

    it('applies a visible focus indicator (outline/border/box-shadow)', () => {
      const rule = ruleDeclarations(/\.toolbar\s+label\.btn:focus-within/)!;
      // Accept any of the common visible focus indicators. `outline: none` does
      // NOT count (it suppresses the indicator); a real outline value does.
      const hasOutline = /outline\s*:\s*(?!none\b)/.test(rule);
      const hasBorder = /border\s*:\s*(?!none\b)/.test(rule);
      const hasBoxShadow = /box-shadow\s*:\s*(?!none\b)/.test(rule);
      const hasBackground = /background\s*:\s*(?!none\b)/.test(rule);
      expect(
        hasOutline || hasBorder || hasBoxShadow || hasBackground,
        ':focus-within must set a visible focus indicator ' +
          '(a non-none outline/border/box-shadow/background)',
      ).toBe(true);
    });
  });
});

